import React from 'react';
import './App.css';

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>Issue Reporter</h1>
        <p>A mobile-optimized web application for reporting facility issues.</p>
        <p>App is starting up...</p>
        <div style={{ marginTop: '20px' }}>
          <h2>Features:</h2>
          <ul style={{ textAlign: 'left' }}>
            <li>Quick reporting via camera</li>
            <li>Issue description submission</li>
            <li>Company response system</li>
            <li>PayPal donation integration</li>
          </ul>
        </div>
      </header>
    </div>
  );
}

export default App;
